                JsonSchemaPathProvider? evaluationPath = null)
            {
                return
                    context.PushChildContext(
                        parentDocument,
                        parentDocumentIndex,
                        useEvaluatedItems: false,
                        useEvaluatedProperties: true,
                        itemIndex,
                        evaluationPath: evaluationPath,
                        schemaEvaluationPath: SchemaLocationProvider);
            }
        }
    }
}
